const body = $json.body ?? $json;
const now = new Date();
const leadName = body.name ?? body.lead_name ?? 'Unknown Lead';
const businessName = body.business_name ?? body.company ?? body.account_name ?? 'Unknown Business';
const leadEmail = body.email ?? body.lead_email ?? null;
const leadPhone = body.phone ?? body.lead_phone ?? null;
const serviceRequested = body.service ?? body.service_requested ?? 'General enquiry';
const message = body.message ?? body.lead_message ?? body.notes ?? '';
const sourceChannel = body.source_channel ?? body.lead_source ?? 'website-form';
const rawUrgency = String(body.urgency ?? 'normal').toLowerCase();
const urgency = ['low','normal','high','emergency'].includes(rawUrgency) ? rawUrgency : 'normal';
const assignedTo = body.assigned_to ?? 'ops';
const alertDestination = $vars.g7TelegramTarget ?? 'CONFIGURE_IN_N8N';
const niche = body.niche ?? 'Home Services';
const requestedDate = body.booking_date ?? body.requested_date ?? body.date ?? null;
const requestedTime = body.booking_time ?? body.requested_time ?? body.time ?? null;
const bookingDurationMinutes = Number(body.booking_duration_minutes ?? body.duration_minutes ?? 60);
const bookingCalendar = body.booking_calendar ?? body.calendar_name ?? 'Work';
const requestType = String(body.inquiry_type ?? body.request_type ?? body.intent ?? '').toLowerCase();
const callNow = body.call_now === true || String(body.call_now ?? '').toLowerCase() === 'true';
const isBooking = requestType.includes('booking') || (!!requestedDate && !!requestedTime);
const isUrgentCall = requestType.includes('urgent') || requestType.includes('call') || callNow || ['urgent', 'emergency'].includes(urgency);
let inquiryType = 'standard';
if (isBooking) inquiryType = 'booking';
else if (isUrgentCall) inquiryType = 'urgent-call';
const bookingDetailsComplete = !!requestedDate && !!requestedTime;
const bookingStatus = inquiryType === 'booking' ? 'requested' : 'not-applicable';
return { json: {
  received_at: now.toISOString(),
  processed_at: now.toISOString(),
  run_id: `run_${Date.now()}`,
  lead_name: leadName,
  business_name: businessName,
  lead_email: leadEmail,
  lead_phone: leadPhone,
  service_requested: serviceRequested,
  message,
  source_channel: sourceChannel,
  urgency,
  assigned_to: assignedTo,
  alert_destination: alertDestination,
  niche,
  inquiry_type: inquiryType,
  requested_booking_date: requestedDate,
  requested_booking_time: requestedTime,
  booking_status: bookingStatus,
  booking_calendar: bookingCalendar,
  booking_duration_minutes: Number.isFinite(bookingDurationMinutes) ? bookingDurationMinutes : 60,
  booking_details_complete: bookingDetailsComplete
} };

const body = $json.body ?? $json;
const fromRaw = String(body.From ?? body.phone ?? '').trim();
const phone = fromRaw.replace(/^whatsapp:/i, '');
const message = String(body.Body ?? body.message ?? '').trim();
const profileName = String(body.ProfileName ?? body.name ?? '').trim();
const messageSid = String(body.MessageSid ?? body.message_sid ?? `WA_${Date.now()}`);
if (!phone) throw new Error('WhatsApp sender phone is missing');
if (!message && Number(body.NumMedia ?? 0) === 0) throw new Error('WhatsApp message body is missing');
return { json: {
  phone,
  message: message || 'Customer sent a WhatsApp media attachment.',
  profile_name: profileName,
  message_sid: messageSid,
  dry_run: body.dry_run === true || String(body.dry_run ?? '').toLowerCase() === 'true'
} };
